#include<bits/stdc++.h>
using namespace std;
long long dp[7][7][7][7][7];
int v[110][7],cnt[7];
int main()
{
    int n,k,p;
    scanf("%d%d%d",&n,&k,&p);
    for(int i=1;i<=k;i++)
    {
        cnt[i]=p;
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0][0][0][0][0]=0;
    for(int i=1;i<=n;i++)
    {
        int w;
        scanf("%d",&w);
        for(int j=1;j<=k;j++)
        {
            scanf("%d",&v[i][j]);
        }
        for(int a=cnt[1];a>=0;a--)
        {
            for(int b=cnt[2];b>=0;b--)
            {
                for(int c=cnt[3];c>=0;c--)
                {
                    for(int d=cnt[4];d>=0;d--)
                    {
                        for(int e=cnt[5];e>=0;e--)
                        {
                            long long &nxt=dp[min(cnt[1],a+v[i][1])][min(cnt[2],b+v[i][2])][min(cnt[3],c+v[i][3])][min(cnt[4],d+v[i][4])][min(cnt[5],e+v[i][5])];
                            nxt=min(nxt,dp[a][b][c][d][e]+w);
                        }
                    }
                }
            }
        }
    }
    if(dp[cnt[1]][cnt[2]][cnt[3]][cnt[4]][cnt[5]]>1e18)
    {
        printf("-1");
        return 0;
    }
    printf("%lld",dp[cnt[1]][cnt[2]][cnt[3]][cnt[4]][cnt[5]]);
    return 0;
}
